pub(super) fn dispatch(
    engine: &Lodestar,
    name: &str,
    args: &Value,
) -> Option<Result<Value, String>> {
    match name {
        "register_design" => Some((|| {
            let item = engine
                .register_design(
                    req_str(args, "adr_path")?,
                    req_str(args, "title")?,
                    opt_str(args, "summary").unwrap_or_default().as_str(),
                )
                .map_err(|e| e.to_string())?;
            ok(&item)
        })()),
        "reconcile_designs" => Some((|| {
            let designs = parse_design_metadata(args)?;
            ok(&engine
                .reconcile_designs(&designs)
                .map_err(|e| e.to_string())?)
        })()),
        "design_board" => Some((|| {
            ok(&engine.design_board().map_err(|e| e.to_string())?)
        })()),
        "list_designs" => Some((|| {
            let status = match opt_str(args, "status") {
                Some(value) => Some(
                    DesignStatus::from_tag(&value)
                        .ok_or_else(|| format!("unknown design status: {value}"))?,
                ),
                None => None,
            };
            ok(&engine
                .list_design_items(status)
                .map_err(|e| e.to_string())?)
        })()),
        "accept_design" => Some((|| {
            let item = engine
                .accept_design(req_str(args, "id")?, req_str(args, "human")?)
                .map_err(|e| e.to_string())?;
            ok(&item)
        })()),
        "reject_design" => Some((|| {
            let item = engine
                .reject_design(
                    req_str(args, "id")?,
                    req_str(args, "human")?,
                    req_str(args, "reason")?,
                )
                .map_err(|e| e.to_string())?;
            ok(&item)
        })()),
        _ => None,
    }
}

fn parse_design_metadata(args: &Value) -> Result<Vec<DesignMetadata>, String> {
    let designs = args
        .get("designs")
        .cloned()
        .ok_or_else(|| "missing required array arg: designs".to_string())?;
    serde_json::from_value(designs).map_err(|error| format!("invalid design metadata: {error}"))
}

#[cfg(test)]
mod tests {
    use super::super::call;
    use lodestar_core::llm::LlmClient;
    use lodestar_core::{GoalKind, Lodestar};
    use serde_json::{json, Value};

    fn engine() -> Lodestar {
        // Unreachable model so plan_design_promotion takes its deterministic
        // single-task fallback — independent of any ambient local model.
        Lodestar::open_in_memory()
            .unwrap()
            .with_agent(Some("planner".to_string()))
            .with_llm(LlmClient::unreachable())
    }

    fn payload(result: Value) -> Value {
        serde_json::from_str(result["content"][0]["text"].as_str().unwrap()).unwrap()
    }

    #[test]
    fn register_accept_promote_round_trips_through_the_tool_surface() {
        let engine = engine();
        let registered = payload(
            call(
                &engine,
                &json!({
                    "name": "register_design",
                    "arguments": {
                        "adr_path": "docs/adr/0023-design-board-accept-bridge.md",
                        "title": "Accept bridge",
                        "summary": "human accept completes design work"
                    }
                }),
            )
            .unwrap(),
        );
        assert_eq!(registered["status"], "proposed");
        let id = registered["id"].as_str().unwrap().to_string();

        let board =
            payload(call(&engine, &json!({ "name": "design_board", "arguments": {} })).unwrap());
        assert_eq!(board.as_array().unwrap().len(), 1);

        let ledger = payload(
            call(
                &engine,
                &json!({ "name": "list_designs", "arguments": { "status": "proposed" } }),
            )
            .unwrap(),
        );
        assert_eq!(ledger.as_array().unwrap().len(), 1);

        // Accept is decision-only: accepted + pending, no tasks, still visible
        // for promotion or retry.
        let accepted = payload(
            call(
                &engine,
                &json!({ "name": "accept_design", "arguments": { "id": id, "human": "reviewer" } }),
            )
            .unwrap(),
        );
        assert_eq!(accepted["status"], "accepted");
        assert_eq!(accepted["promotion_status"], "pending");
        let pending =
            payload(call(&engine, &json!({ "name": "design_board", "arguments": {} })).unwrap());
        assert_eq!(pending.as_array().unwrap().len(), 1);
        assert_eq!(pending[0]["promotion_status"], "pending");

        // Planning is read-only; only the reviewed plan materialises work.
        let objective = engine
            .define_goal(GoalKind::Objective, "Ship the bridge", "wire it", None)
            .unwrap();
        let plan = payload(
            call(
                &engine,
                &json!({
                    "name": "plan_design_promotion",
                    "arguments": { "id": id, "objective_goal_id": objective.id }
                }),
            )
            .unwrap(),
        );
        assert!(engine.next_task().unwrap().is_none());
        let promo = payload(
            call(
                &engine,
                &json!({
                    "name": "promote_design",
                    "arguments": { "id": id, "plan": plan }
                }),
            )
            .unwrap(),
        );
        assert_eq!(promo["item"]["promotion_status"], "materialized");
        assert_eq!(promo["goals"][0]["id"], objective.id);
        assert!(!promo["tasks"].as_array().unwrap().is_empty());
        let persisted = payload(
            call(
                &engine,
                &json!({ "name": "design_promotion", "arguments": { "id": id } }),
            )
            .unwrap(),
        );
        assert_eq!(persisted["goals"][0]["id"], objective.id);
        assert_eq!(persisted["tasks"], promo["tasks"]);
        assert_eq!(persisted["constraints"], promo["constraints"]);
        assert!(payload(
            call(&engine, &json!({ "name": "design_board", "arguments": {} })).unwrap()
        )
        .as_array()
        .unwrap()
        .is_empty());
        let history = payload(
            call(
                &engine,
                &json!({ "name": "design_materialization_history", "arguments": { "id": id } }),
            )
            .unwrap(),
        );
        assert_eq!(history.as_array().unwrap().len(), 1);
    }

    #[test]
    fn accept_design_rejects_a_self_decision_at_the_tool_boundary() {
        let engine = engine();
        let registered = payload(
            call(
                &engine,
                &json!({
                    "name": "register_design",
                    "arguments": { "adr_path": "docs/adr/0099-self.md", "title": "Self" }
                }),
            )
            .unwrap(),
        );
        let id = registered["id"].as_str().unwrap().to_string();
        let err = call(
            &engine,
            &json!({ "name": "accept_design", "arguments": { "id": id, "human": "planner" } }),
        )
        .unwrap_err();
        assert!(err.contains("own design"));
    }

    #[test]
    fn promote_registers_mandated_constraints_through_the_tool() {
        let engine = engine();
        let registered = payload(
            call(
                &engine,
                &json!({
                    "name": "register_design",
                    "arguments": { "adr_path": "docs/adr/0030-typed.md", "title": "Typed errors" }
                }),
            )
            .unwrap(),
        );
        let id = registered["id"].as_str().unwrap().to_string();
        call(
            &engine,
            &json!({ "name": "accept_design", "arguments": { "id": id, "human": "reviewer" } }),
        )
        .unwrap();
        let objective = engine
            .define_goal(GoalKind::Objective, "Type the errors", "do it", None)
            .unwrap();
        let mut plan = payload(
            call(
                &engine,
                &json!({
                    "name": "plan_design_promotion",
                    "arguments": { "id": id, "objective_goal_id": objective.id }
                }),
            )
            .unwrap(),
        );
        plan["constraints"] = json!([
            { "kind": "constraint", "title": "No unwrap", "statement": "no unwrap in prod" }
        ]);
        let promo = payload(
            call(
                &engine,
                &json!({
                    "name": "promote_design",
                    "arguments": { "id": id, "plan": plan }
                }),
            )
            .unwrap(),
        );
        let constraints = promo["constraints"].as_array().unwrap();
        assert_eq!(constraints.len(), 1);
        assert_eq!(constraints[0]["kind"], "constraint");
    }

    #[test]
    fn revise_design_promotion_links_existing_work_and_preserves_history() {
        let engine = engine();
        let goal = engine
            .define_goal(GoalKind::Objective, "Existing work", "reuse it", None)
            .unwrap();
        let existing = engine
            .create_task(&goal.id, "Authoritative task", "done")
            .unwrap();
        let registered = payload(
            call(
                &engine,
                &json!({
                    "name": "register_design",
                    "arguments": { "adr_path": "docs/adr/0105-repair.md", "title": "Repair" }
                }),
            )
            .unwrap(),
        );
        let id = registered["id"].as_str().unwrap();
        call(
            &engine,
            &json!({ "name": "accept_design", "arguments": { "id": id, "human": "reviewer" } }),
        )
        .unwrap();
        let create_plan = payload(
            call(
                &engine,
                &json!({
                    "name": "plan_design_promotion",
                    "arguments": { "id": id, "objective_goal_id": goal.id }
                }),
            )
            .unwrap(),
        );
        call(
            &engine,
            &json!({ "name": "promote_design", "arguments": { "id": id, "plan": create_plan } }),
        )
        .unwrap();

        let revised = payload(
            call(
                &engine,
                &json!({
                    "name": "revise_design_promotion",
                    "arguments": {
                        "id": id,
                        "human": "second-reviewer",
                        "plan": {
                            "mode": "link",
                            "task_ids": [existing.id],
                            "rationale": "The implementation task already existed"
                        }
                    }
                }),
            )
            .unwrap(),
        );
        assert_eq!(revised["revision"], 2);
        assert_eq!(revised["tasks"][0]["id"], existing.id);
        let history = payload(
            call(
                &engine,
                &json!({ "name": "design_materialization_history", "arguments": { "id": id } }),
            )
            .unwrap(),
        );
        assert_eq!(history.as_array().unwrap().len(), 2);
        assert_eq!(history[1]["plan"]["mode"], "link");
    }

    #[test]
    fn reconcile_designs_is_idempotent_and_never_creates_tasks() {
        let engine = engine();
        let arguments = json!({
            "designs": [
                {
                    "adr_path": "docs/adr/0026-constitution.md",
                    "title": "Constitution",
                    "summary": "review governance",
                    "status": "proposed",
                    "proposed_by": "workspace-sensor"
                },
                {
                    "adr_path": "docs/adr/0001-historical.md",
                    "title": "Historical",
                    "status": "accepted"
                },
                {
                    "adr_path": "docs/adr/0002-rejected.md",
                    "title": "Rejected",
                    "status": "rejected"
                }
            ]
        });

        let first = payload(
            call(
                &engine,
                &json!({ "name": "reconcile_designs", "arguments": arguments }),
            )
            .unwrap(),
        );
        let retry = payload(
            call(
                &engine,
                &json!({ "name": "reconcile_designs", "arguments": arguments }),
            )
            .unwrap(),
        );
        assert_eq!(first, retry);
        assert_eq!(first.as_array().unwrap().len(), 3);
        assert!(first
            .as_array()
            .unwrap()
            .iter()
            .all(|item| item["promotion_status"] == "not_required"));
        assert!(engine.next_task().unwrap().is_none());

        let board =
            payload(call(&engine, &json!({ "name": "design_board", "arguments": {} })).unwrap());
        assert_eq!(board.as_array().unwrap().len(), 1);
        assert_eq!(board[0]["id"], "design:0026-constitution");
    }
}
